sys_script_include.script:
var discordNotification = Class.create();
discordNotification.prototype = {
    initialize: function() {
        // Get webhook URL from system property
        this.webhookURL = gs.getProperty('x_451445_wrm.discord.webhook_url');
    },
    sendMessage: function(message, emoji) {
        // Don't send if webhook not configured
        if (!this.webhookURL) {
            gs.warn('Discord webhook URL not configured');
            return false;
        }
        try {
            var request = new sn_ws.RESTMessageV2();
            request.setEndpoint(this.webhookURL);
            request.setHttpMethod('POST');
            request.setRequestHeader('Content-Type', 'application/json');
            // Build Discord message payload
            var payload = {
                content: (emoji ? emoji + ' ' : '') + message
            };
            request.setRequestBody(JSON.stringify(payload));

		    var response = request.execute();
            var httpStatus = response.getStatusCode();

			if (httpStatus == 200 || httpStatus == 204) {
                gs.info('Discord notification sent successfully');
                return true;
            } else {
                gs.error('Discord notification failed with status: ' +
                    httpStatus);
                return false;
            }
        } catch (ex) {
            gs.error('Error sending Discord notification: ' + ex.message);
            return false;
        }

    },

    type: 'discordNotification'
};
